function createPlanet(data, index) {
  // Planet sphere
  const geometry = new THREE.SphereGeometry(data.size, 48, 48);
  let material;

  // Try to load texture
  const texPromise = new Promise((resolve) => {
    textureLoader.load(data.textureUrl,
      (tex) => { resolve(tex); },
      undefined,
      () => { resolve(null); }
    );
  });

  texPromise.then((tex) => {
    if (tex) {
      tex.colorSpace = THREE.SRGBColorSpace;
      material = new THREE.MeshStandardMaterial({ map: tex, roughness: 0.8 });
      if (planetMeshes[index]) {
        planetMeshes[index].material = material;
      }
    }
  });

  if (!texPromise) {
    material = new THREE.MeshStandardMaterial({ color: data.color, roughness: 0.8 });
  } else {
    material = new THREE.MeshStandardMaterial({ color: data.color, roughness: 0.8 });
  }

  const mesh = new THREE.Mesh(geometry, material);
  mesh.userData = { planetIndex: index, planetData: data };

  // Create a group to hold planet + label
  const group = new THREE.Group();
  group.add(mesh);

  // Axial tilt
  group.rotation.z = data.axialTilt;

  scene.add(group);
  planetMeshes[index] = group;

